    /// <summary>
    /// Translation tables for the fork UI. Add entries with E(key, en, fr, es, de).
    /// Keys are namespaced by module (e.g. "WebUsers.Title"). English is the source/fallback.
    /// </summary>
    internal static class LocStrings
